	curl_batch($requests);
}

function td_publications_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('td_publications', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: td_publications_before_delete
	if(function_exists('td_publications_before_delete')) {
		$args = [];
		if(!td_publications_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `td_publications` WHERE `id`='{$selected_id}'", $eo);

	// hook: td_publications_after_delete
	if(function_exists('td_publications_after_delete')) {
		$args = [];
		td_publications_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='td_publications' AND `pkValue`='{$selected_id}'", $eo);
}

function td_publications_update(&$selected_id, &$error_message = '') {
